                       </div>
                       <div className="hidden md:flex gap-2">
                         {study.techStack.map(tech => (
                           <span key={tech} className="px-3 py-1 bg-slate-950 rounded-full text-xs text-slate-400 border border-slate-800">
                             {tech}
                           </span>
